497	func getUint64HeaderValue(record *kgo.Record, headerKey string) (uint64, error) {
498		if headerKey == "" {
499			return 0, nil
500		}
501		headerValue := getHeaderValue(record, headerKey)
502		if headerValue == "" {
503			return 0, nil
504		}
505		value, err := strconv.ParseUint(headerValue, 10, 64)
506		if err != nil {
507			return 0, fmt.Errorf("error parsing header %s value %s: %w", headerKey, headerValue, err)
508		}
509		return value, nil
510	}
511	
512	func getBoolHeaderValue(record *kgo.Record, headerKey string) (bool, error) {
513		if headerKey == "" {
514			return false, nil
515		}
516		headerValue := getHeaderValue(record, headerKey)
517		if headerValue == "" {
518			return false, nil
519		}
520		value, err := strconv.ParseBool(headerValue)
521		if err != nil {
522			return false, fmt.Errorf("error parsing header %s value %s: %w", headerKey, headerValue, err)
523		}
524		return value, nil
525	}
526	
527	func getHeaderValue(record *kgo.Record, headerKey string) string {
528		if headerKey == "" {
529			return ""
530		}
531		for _, header := range record.Headers {
532			if header.Key == headerKey {
533				return string(header.Value)
534			}
535		}
536		return ""
537	}
538	
539	func publicationTagsFromKafkaRecord(record *kgo.Record, tagsHeaderPrefix string) map[string]string {
540		if tagsHeaderPrefix == "" {
541			return nil
542		}
543		var tags map[string]string
544		for _, header := range record.Headers {
545			if strings.HasPrefix(header.Key, tagsHeaderPrefix) {
546				if tags == nil {
547					tags = make(map[string]string)
548				}
549				tags[header.Key[len(tagsHeaderPrefix):]] = string(header.Value)
550			}
551		}
552		return tags
553	}
554	
555	func (pc *partitionConsumer) processPublicationDataRecord(ctx context.Context, record *kgo.Record) error {
556		data := record.Value
557		idempotencyKey := getHeaderValue(record, pc.config.PublicationDataMode.IdempotencyKeyHeader)
558		delta, err := getBoolHeaderValue(record, pc.config.PublicationDataMode.DeltaHeader)
559		if err != nil {
560			pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Msg("error parsing delta header value, skip message")
561			return nil
562		}
563		channelsHeader := getHeaderValue(record, pc.config.PublicationDataMode.ChannelsHeader)
564		if channelsHeader == "" {
565			pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("no channels found, skip message")
566			return nil
567		}
568		channels := strings.Split(channelsHeader, ",")
569		if len(channels) == 0 || (len(channels) == 1 && channels[0] == "") {
570			pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("no channels found, skip message")
571			return nil
572		}
573		version, err := getUint64HeaderValue(record, pc.config.PublicationDataMode.VersionHeader)
574		if err != nil {
575			pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Msg("error parsing version header value, skip message")
576			return nil
577		}
578		return pc.dispatcher.DispatchPublication(
579			ctx,
580			channels,
581			api.ConsumedPublication{
582				Data:           data,
583				IdempotencyKey: idempotencyKey,
584				Delta:          delta,
585				Tags:           publicationTagsFromKafkaRecord(record, pc.config.PublicationDataMode.TagsHeaderPrefix),
586				Version:        version,
587				VersionEpoch:   getHeaderValue(record, pc.config.PublicationDataMode.VersionEpochHeader),
588			},
589		)
590	}
591	
592	func (pc *partitionConsumer) processRecord(ctx context.Context, record *kgo.Record) error {
593		if pc.config.PublicationDataMode.Enabled {
594			return pc.processPublicationDataRecord(ctx, record)
595		}
596		method := getHeaderValue(record, pc.config.MethodHeader)
597		return pc.dispatcher.DispatchCommand(ctx, method, record.Value)
598	}
599	
600	func (pc *partitionConsumer) processRecords(records []*kgo.Record) {
601		for _, record := range records {
602			select {
603			case <-pc.partitionCtx.Done():
604				return
605			default:
606			}
607	
608			var backoffDuration time.Duration = 0
609			retries := 0
610			for {
611				err := pc.processRecord(pc.partitionCtx, record)
612				if err == nil {
613					if retries > 0 {
614						pc.common.log.Info().Str("topic", record.Topic).Int32("partition", record.Partition).Msg("OK processing message after errors")
615					}
616					if logging.Enabled(logging.TraceLevel) {
617						pc.common.log.Trace().Str("topic", record.Topic).Int32("partition", record.Partition).Int64("offset", record.Offset).Msg("record processed")
618					}
619					metrics.ConsumerProcessedTotal.WithLabelValues(pc.name).Inc()
620					pc.cl.MarkCommitRecords(record)
621					break
622				}
623				if errors.Is(err, context.Canceled) {
624					return
625				}
626				retries++
627				backoffDuration = getNextBackoffDuration(backoffDuration, retries)
628				metrics.ConsumerErrorsTotal.WithLabelValues(pc.name).Inc()
629				pc.common.log.Error().Err(err).Str("topic", record.Topic).Int32("partition", record.Partition).Str("next_attempt_in", backoffDuration.String()).Msg("error processing consumed record")
630				select {
631				case <-time.After(backoffDuration):
632				case <-pc.partitionCtx.Done():
633					return
634				}
635			}
636		}
637	}
638	
639	func (pc *partitionConsumer) consume() {
640		if logging.Enabled(logging.DebugLevel) {
641			pc.common.log.Debug().Str("topic", pc.topic).Int32("partition", pc.partition).Msg("starting partition consumer")
642		}
643		defer close(pc.done)
644		defer pc.queue.Close()
645		defer func() {
646			if logging.Enabled(logging.DebugLevel) {
647				// Queue is closed, partition consumer is shutting down.
648				pc.common.log.Debug().Str("topic", pc.topic).Int32("partition", pc.partition).Msg("partition consumer shutting down")
649			}
650		}()
651	
652		partitionsToResume := map[string][]int32{pc.topic: {pc.partition}}
653		resumeConsuming := func() {
654			pc.cl.ResumeFetchPartitions(partitionsToResume)
655		}
656		defer resumeConsuming()
657	
658		for {
659			select {
660			case <-pc.partitionCtx.Done():
661				return
662			case <-pc.queue.NotEmpty():
663				if pc.queue.IsClosed() {
664					return
665				}
666				// Process all available items in the queue.
667				for {
668					select {
669					case <-pc.partitionCtx.Done():
670						return
671					default:
672					}
673					p, ok := pc.queue.Pop()
674					if !ok {
675						break
676					}
677					pc.processRecords(p.Records)
678					// Resume partition after processing this batch. Only one additional batch will
679					// be added to the queue before we pause again.
680					resumeConsuming()
681				}
682			}
683		}
684	}
685	
686	// unboundedQueue implements an unbounded queue for FetchTopicPartition
687	type unboundedQueue struct {
688		mu         sync.RWMutex
689		items      []kgo.FetchTopicPartition
690		numRecords int
691		notEmpty   chan struct{}
692		closed     bool
693	}
694	
695	func newUnboundedQueue() *unboundedQueue {
696		return &unboundedQueue{
697			items:    make([]kgo.FetchTopicPartition, 0),
698			notEmpty: make(chan struct{}, 1),
699		}
700	}
701	
702	func (q *unboundedQueue) Push(item kgo.FetchTopicPartition) bool {
703		q.mu.Lock()
704		defer q.mu.Unlock()
705	
706		if q.closed {
707			return false
708		}
709	
710		q.items = append(q.items, item)
711		q.numRecords += len(item.Records)
712	
713		// Signal that queue is not empty.
714		select {
715		case q.notEmpty <- struct{}{}:
716		default:
717		}
718	
719		return true
720	}
721	
722	func (q *unboundedQueue) Pop() (kgo.FetchTopicPartition, bool) {
723		q.mu.Lock()
724		defer q.mu.Unlock()
725	
726		if q.closed || len(q.items) == 0 {
727			return kgo.FetchTopicPartition{}, false
728		}
729	
730		// We do not expect many items in the queue, so we can use a simple slice pop operation and
731		// not worry about memory being reserved for the underlying slice.
732		item := q.items[0]
733		q.items[0] = kgo.FetchTopicPartition{} // Clear the first item for faster GC.
734		q.items = q.items[1:]
735		q.numRecords -= len(item.Records)
736	
737		return item, true
738	}
739	
740	func (q *unboundedQueue) NumRecords() int {
741		q.mu.RLock()
742		defer q.mu.RUnlock()
743		return q.numRecords
744	}
745	
746	func (q *unboundedQueue) Close() {
747		q.mu.Lock()
748		defer q.mu.Unlock()
749	
750		if !q.closed {
751			q.closed = true
752			close(q.notEmpty)
753		}
754	}
755	
756	func (q *unboundedQueue) IsClosed() bool {
757		q.mu.RLock()
758		defer q.mu.RUnlock()
759		return q.closed
760	}
761	
762	func (q *unboundedQueue) NotEmpty() <-chan struct{} {
763		return q.notEmpty
764	}
765	

