	"github.com/centrifugal/centrifugo/v6/internal/configtypes"
	"github.com/rs/zerolog/log"
)

// testLogger creates a simple test logger for unit tests.
func testLogger() *consumerCommon {
	return &consumerCommon{
		name: "test",
		log:  log.With().Str("consumer", "test").Logger(),
	}
}

// TestKafkaConsumer_AssumeRoleARNConfig verifies that the KafkaConsumerConfig
// struct has AssumeRoleARN and CredentialsProfile fields, and that they can be
// set in the configuration.
func TestKafkaConsumer_AssumeRoleARNConfig(t *testing.T) {
	cfg := configtypes.KafkaConsumerConfig{
		Brokers:            []string{"localhost:9092"},
		Topics:             []string{"test-topic"},
		ConsumerGroup:      "test-group",
		SASLMechanism:      "aws-msk-iam",
		AssumeRoleARN:      "arn:aws:iam::123456789012:role/test-role",
		CredentialsProfile: "test-profile",
	}

	if cfg.AssumeRoleARN != "arn:aws:iam::123456789012:role/test-role" {
		t.Errorf("expected AssumeRoleARN to be set correctly")
	}
	if cfg.CredentialsProfile != "test-profile" {
		t.Errorf("expected CredentialsProfile to be set correctly")
	}
	if cfg.SASLMechanism != "aws-msk-iam" {
		t.Errorf("expected SASLMechanism to be aws-msk-iam")
	}
}

// TestKafkaConsumer_InitClientWithAssumeRoleARN verifies that initializing a
// Kafka consumer with assume_role_arn fails predictably when AWS is not
// available (e.g., no real STS endpoint), rather than crashing.
func TestKafkaConsumer_InitClientWithAssumeRoleARN(t *testing.T) {
	cfg := configtypes.KafkaConsumerConfig{
		Brokers:            []string{"localhost:9092"},
		Topics:             []string{"test-topic"},
		ConsumerGroup:      "test-group",
		SASLMechanism:      "aws-msk-iam",
		AssumeRoleARN:      "arn:aws:iam::123456789012:role/test-role",
		CredentialsProfile: "nonexistent-profile",
	}

	// We expect this to fail because there's no real AWS profile, but it should
	// not panic. The error should be about loading AWS config or connecting to
	// Kafka, not about missing fields or type errors.
	_, err := NewKafkaConsumer(cfg, nil, testCommon(nil))
	if err == nil {
		t.Log("unexpected: consumer was created (this is fine if AWS creds are available)")
	} else {
		t.Logf("expected error (no real AWS/Kafka available): %v", err)
	}
}

// TestKafkaConsumer_BackwardCompatibility verifies that the original
// aws-msk-iam configuration (without assume_role_arn) still works as before.
func TestKafkaConsumer_BackwardCompatibility(t *testing.T) {
	cfg := configtypes.KafkaConsumerConfig{
		Brokers:       []string{"localhost:9092"},
		Topics:        []string{"test-topic"},
		ConsumerGroup: "test-group",
		SASLMechanism: "aws-msk-iam",
		SASLUser:      "AKIAIOSFODNN7EXAMPLE",
		SASLPassword:  "wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY",
	}

	// With no AssumeRoleARN, should use the direct access key/secret key path.
	if cfg.AssumeRoleARN != "" {
		t.Errorf("expected AssumeRoleARN to be empty for backward compatibility")
	}

	_, err := NewKafkaConsumer(cfg, nil, testCommon(nil))
	if err == nil {
		t.Log("unexpected: consumer was created (this is fine if Kafka is available)")
	} else {
		t.Logf("expected error (no real Kafka broker available): %v", err)
	}
}

